import {
  NotificationContentType,
  NotificationData,
  NotificationMedia,
  NotificationType,
} from '../consts';
import { getAppLink, getAssetName } from '../lib';
import { BuybackRequestStatus } from '@/db/entities/buyback-request.entity';

type Data = NotificationData<
  | NotificationType.BuybackRequestMinorEvent
  | NotificationType.BuybackRequestMajorEvent
>;

const BB_REQUEST_STATUS_TO_EVENT_NAME: Record<BuybackRequestStatus, string> = {
  [BuybackRequestStatus.New]: 'New',
  [BuybackRequestStatus.PendingValuation]: 'Pending Valuation',
  [BuybackRequestStatus.ValuationReceived]: 'Valuation Received',
  [BuybackRequestStatus.PreAuthOfferSent]: 'Pre-auth Offer Sent',
  [BuybackRequestStatus.PreAuthOfferAccepted]: 'Pre-auth Offer Accepted',
  [BuybackRequestStatus.AssetReceived]: 'Asset Received',
  [BuybackRequestStatus.PendingAuth]: 'Pending Auth',
  [BuybackRequestStatus.AuthCompleted]: 'Auth Completed',
  [BuybackRequestStatus.PendingEntrupy]: 'Pending Entrupy Verification',
  [BuybackRequestStatus.FinalOfferSent]: 'Final Offer Sent',
  [BuybackRequestStatus.KycApproved]: 'KYC Approved',
  [BuybackRequestStatus.KycPending]: 'KYC Pending',
  [BuybackRequestStatus.FinalOfferAccepted]: 'Final Offer Accepted',
  [BuybackRequestStatus.TransactionPending]: 'Transaction Pending',
  [BuybackRequestStatus.PreAuthVerificationFailed]:
    'Pre-auth Verification Failed',
  [BuybackRequestStatus.PostAuthVerificationFailed]:
    'Post-auth Verification Failed',
  [BuybackRequestStatus.KYCFailed]: 'KYC Failed',
  [BuybackRequestStatus.RejectedPreAuthOffer]: 'Rejected Pre-auth Offer',
  [BuybackRequestStatus.RejectedPostAuthOffer]: 'Rejected Post-auth Offer',
  [BuybackRequestStatus.PreAuthOfferExpired]: 'Pre-auth Offer Expired',
  [BuybackRequestStatus.PostAuthOfferExpired]: 'Final Offer Expired',
};

export const BUYBACK_REQUEST_EVENT_CONTENT: NotificationContentType = {
  [NotificationMedia.Email]: (data: Data) => ({
    // subject: `LuxFlow: ${BB_REQUEST_STATUS_TO_EVENT_NAME[data.status]} for ${getAssetName(data.asset)}`,
    subject: `LuxFlow: ${BB_REQUEST_STATUS_TO_EVENT_NAME[data.status]}`,
    // text: `Your buyback request for asset ${getAssetName(data.asset)} has reached a new status: "${BB_REQUEST_STATUS_TO_EVENT_NAME[data.status]}"`,
    text: `Your buyback request has reached a new status: "${BB_REQUEST_STATUS_TO_EVENT_NAME[data.status]}"`,
    link: {
      url: getAppLink(`quote-request/${data.buybackRequestId}`),
      text: 'View Request',
    },
  }),
  [NotificationMedia.InApp]: (data: Data) => ({
    title: 'Buyback Request Update',
    // body: `Your buyback request for asset ${getAssetName(data.asset)} has reached a new status: ${BB_REQUEST_STATUS_TO_EVENT_NAME[data.status]}`,
    body: `Your buyback request has reached a new status: ${BB_REQUEST_STATUS_TO_EVENT_NAME[data.status]}`,
  }),
  [NotificationMedia.Phone]: (data: Data) =>
    // `Your buyback request for asset ${getAssetName(data.asset)} has reached a new status: ${BB_REQUEST_STATUS_TO_EVENT_NAME[data.status]}`,
    `Your buyback request has reached a new status: ${BB_REQUEST_STATUS_TO_EVENT_NAME[data.status]}`,
};

