1	import {
2	  BadRequestException,
3	  Injectable,
4	  Logger,
5	  NotFoundException,
6	} from '@nestjs/common';
7	
8	import { TransactionHost } from '@nestjs-cls/transactional';
9	
10	import { ContextService, TransactionalAdapterTypeOrm } from '@/modules/global';
11	
12	import {
13	  AccountType,
14	  AssetEntity,
15	  AssetHandoverOption,
16	  AssetHandoverType,
17	  AssetStatus,
18	  AssetValuationEntity,
19	  AssetValuationStatus,
20	  AuthenticatorCategoryEntity,
21	  BuybackEntity,
22	  BuybackExtensionEntity,
23	  BuybackExtensionType,
