25	  BuybackRequestEntity,
26	  BuybackRequestStage,
27	  BuybackRequestStatus,
28	  BuybackStatus,
29	  BuybackType,
30	  EntryDirection,
31	  KycEntity,
32	  KycStatus,
33	  LedgerTransactionType,
34	  UserEntity,
35	  UserSetting,
36	} from '@/db';
37	import { DEFAULT_CURRENCY, convertMinorUnits } from '@/common/currency';
38	import { ListQuery } from '@/utils';
39	import {
40	  AcceptPreAuthOfferDto,
41	  BuybackSearchFilters,
42	  RejectPostAuthOfferDto,
43	  RejectPreAuthOfferDto,
44	} from '../types';
45	import { Brackets } from 'typeorm';
46	import {
47	  addBbRequestEvent,
48	  getBbComputedDetails,
