55	import { NotificationService, NotificationType } from '@/modules/notification';
56	
57	@Injectable()
58	export class BuybackRequestService {
59	  private logger = new Logger(BuybackRequestService.name);
60	
61	  constructor(
62	    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
63	    private readonly contextService: ContextService,
64	    private readonly ledgerService: LedgerService,
65	    private readonly feeCalculationService: BuybackFeeCalculationService,
66	    private readonly assetHandoverService: AssetHandoverService,
67	    private readonly notificationService: NotificationService,
68	  ) { }
69	
70	  async markAssetShipped(buybackRequestId: string) {
71	    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
72	    const buybackRepo = this.txHost.tx.getRepository(BuybackEntity);
73	
74	    const bbRequest = await repository.findOne({
75	      where: { id: buybackRequestId },
76	      relations: [
77	        'buyback',
78	        'buyback.asset',
79	        'buyback.asset.category',
80	      ],
81	    });
82	
83	    if (!bbRequest || !bbRequest.buyback) {
84	      throw new NotFoundException('Buyback request not found');
85	    }
86	
87	    await buybackRepo.save({
88	      id: bbRequest.buyback.id,
89	      status: BuybackStatus.SelfDropShipped,
90	      computedDetails: {
91	        ...bbRequest.buyback.computedDetails,
92	        shipmentOn: new Date(),
93	      },
94	    });
95	
96	    await this.notificationService.send(
97	      'admins',
98	      NotificationType.BuybackAdminMinorEvent,
99	      {
100	        buybackId: bbRequest.buyback.id,
101	        asset: {
102	          categoryName: bbRequest.buyback.asset?.category?.name ?? null,
103	        },
104	        status: BuybackStatus.SelfDropShipped,
105	      },
106	    );
107	  }
108	
109	  async confirmAssetPickedUp(buybackRequestId: string) {
110	    return this.txHost.withTransaction(async () => {
111	      const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
112	      const buybackRepo = this.txHost.tx.getRepository(BuybackEntity);
113	      const assetRepo = this.txHost.tx.getRepository(AssetEntity);
114	
115	      const bbRequest = await repository.findOne({
116	        where: { id: buybackRequestId },
117	        relations: [
118	          'buyback',
119	          'buyback.asset',
120	          'buyback.asset.category',
121	        ],
122	      });
123	
124	      if (!bbRequest || !bbRequest.buyback) {
125	        throw new NotFoundException('Buyback request not found');
126	      }
127	
128	      await buybackRepo.save({
129	        id: bbRequest.buyback.id,
130	        status: BuybackStatus.AssetPickedUp,
131	        computedDetails: {
132	          ...bbRequest.buyback.computedDetails,
133	          pickedUp: new Date(),
134	        },
135	      });
136	
137	      await assetRepo.save({
138	        id: bbRequest.buyback.assetId,
139	        status: AssetStatus.PendingReturn,
140	      });
141	
142	      await this.notificationService.send(
143	        'admins',
144	        NotificationType.BuybackAdminMinorEvent,
145	        {
146	          buybackId: bbRequest.buyback.id,
147	          asset: {
148	            categoryName: bbRequest.buyback.asset?.category?.name ?? null,
149	          },
150	          status: BuybackStatus.AssetPickedUp,
151	        },
152	      );
153	    });
154	  }
155	
156	  // Stage 1
157	  async create() {
158	    const buybackRequestRepository =
159	      this.txHost.tx.getRepository(BuybackRequestEntity);
160	
161	    const stage = BuybackRequestStage.Quote;
162	    const status = BuybackRequestStatus.New;
163	    const eventsLog = addBbRequestEvent([], status);
164	
165	    return buybackRequestRepository.save({
166	      stage,
167	      status,
168	      eventsLog,
169	    });
170	  }
171	
172	  async getMany(listQuery: ListQuery, filters?: BuybackSearchFilters) {
173	    const userId = this.contextService.context.user.id;
174	
175	    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
176	
177	    const query = repository
178	      .createQueryBuilder('buyback_request')
179	      .select([
180	        'buyback_request.id',
181	        'buyback_request.status',
182	        'buyback_request.stage',
183	        'buyback_request.createdAt',
184	      ])
185	      .leftJoin('buyback_request.buyback', 'buyback')
186	      .addSelect(['buyback.id', 'buyback.type', 'buyback.status'])
187	      .where('buyback.sellerId = :userId', { userId })
188	      .andWhere('buyback.status = :status', { status: BuybackStatus.Quote })
189	      .leftJoin('buyback.asset', 'asset')
190	      .addSelect(['asset.id', 'asset.meta', 'asset.categoryFields'])
191	      .leftJoin('asset.category', 'category')
192	      .addSelect(['category.id', 'category.name'])
193	      .leftJoin('asset.photos', 'photos')
194	      .addSelect(['photos.id'])
195	      .skip(listQuery.skip)
196	      .take(listQuery.take)
197	      .orderBy('buyback_request.createdAt', listQuery?.order || 'DESC');
198	
199	    if (filters?.types) {
200	      query.andWhere('buyback.type IN (:...types)', { types: filters.types });
201	    }
202	
203	    if (filters?.categories) {
204	      query.andWhere('category.id IN (:...categories)', {
205	        categories: filters.categories,
206	      });
207	    }
208	
209	    if (filters?.search) {
210	      query.andWhere(
211	        new Brackets((qb) => {
212	          qb.where('category.name ILIKE :search')
213	            .orWhere("asset.categoryFields->>'brandName' ILIKE :search")
214	            .orWhere("asset.categoryFields->>'modelName' ILIKE :search");
215	        }),
216	        { search: `%${filters.search}%` },
217	      );
218	    }
219	
220	    const [results, total] = await query.getManyAndCount();
221	
222	    return {
223	      total,
224	      data: results,
225	      skip: listQuery.skip,
226	      take: listQuery.take,
227	    };
228	  }
229	
230	  async getOne(buybackRequestId: string) {
231	    const userId = this.contextService.context.user.id;
232	    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
233	
234	    const buybackRequest = await repository
235	      .createQueryBuilder('buyback_request')
236	      .select([
237	        'buyback_request.id',
238	        'buyback_request.status',
239	        'buyback_request.stage',
240	        'buyback_request.createdAt',
241	        'buyback_request.rejectReason',
242	        'buyback_request.eventsLog',
243	      ])
244	      .where('buyback_request.id = :id', { id: buybackRequestId })
245	      .andWhere('buyback.sellerId = :userId', { userId })
246	      .leftJoin('buyback_request.buyback', 'buyback')
247	      .addSelect(['buyback.id', 'buyback.type', 'buyback.status'])
248	      .leftJoin('buyback.asset', 'asset')
249	      .addSelect([
250	        'asset.id',
251	        'asset.categoryFields',
252	        'asset.extras',
253	        'asset.meta',
254	        'asset.declarationFormId',
255	      ])
256	      .leftJoin('asset.category', 'category')
257	      .addSelect(['category.id', 'category.name'])
258	      .leftJoin('asset.photos', 'photos')
259	      .addSelect(['photos.id'])
260	      .leftJoin('buyback_request.preAuthOffer', 'preAuthOffer')
261	      .addSelect([
262	        'preAuthOffer.id',
263	        'preAuthOffer.data',
264	        'preAuthOffer.type',
265	        'preAuthOffer.expiresAt',
266	      ])
267	      .leftJoin('buyback_request.postAuthOffer', 'postAuthOffer')
268	      .addSelect([
269	        'postAuthOffer.id',
270	        'postAuthOffer.data',
271	        'postAuthOffer.type',
272	        'postAuthOffer.expiresAt',
273	      ])
274	      .leftJoin('asset.handovers', 'handovers')
275	      .addSelect([
276	        'handovers.id',
277	        'handovers.option',
278	        'handovers.type',
279	        'handovers.status',
280	        'handovers.courierPartnerId',
281	        'handovers.courierNumber',
282	        'handovers.visitDate',
283	      ])
284	      .leftJoin('handovers.courierPartner', 'courierPartner')
285	      .addSelect(['courierPartner.id', 'courierPartner.name'])
286	      .leftJoin('handovers.toCustodyLocation', 'toCustodyLocation')
287	      .addSelect(['toCustodyLocation.id', 'toCustodyLocation.name'])
288	      .leftJoin('toCustodyLocation.custody', 'custody')
289	      .addSelect(['custody.id', 'custody.name'])
290	      .getOne();
291	
292	    if (!buybackRequest) {
293	      throw new NotFoundException('Buyback request not found');
294	    }
295	
296	    return buybackRequest;
297	  }
298	
299	  // Stage 4a
300	  async acceptPreAuthOffer(
301	    buybackRequestId: string,
302	    dto: AcceptPreAuthOfferDto,
303	  ) {
304	    const status = BuybackRequestStatus.PreAuthOfferAccepted;
305	
306	    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
307	    const userId = this.contextService.context.user.id;
308	
309	    const buybackRequest = await repository.findOne({
310	      where: { id: buybackRequestId, buyback: { sellerId: userId } },
311	      select: ['id', 'status', 'eventsLog'],
312	      relations: [
313	        'buyback',
314	        'buyback.asset',
315	        'buyback.asset.category',
316	      ],
317	    });
318	
319	    if (!buybackRequest) {
320	      throw new NotFoundException('Buyback request not found');
321	    }
322	
323	    if (buybackRequest.status !== BuybackRequestStatus.PreAuthOfferSent) {
324	      throw new BadRequestException('Invalid request status');
325	    }
326	
327	    const eventsLog = addBbRequestEvent(buybackRequest.eventsLog.data, status);
328	
329	    return this.txHost.withTransaction(async () => {
330	      const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
331	      const assetRepository = this.txHost.tx.getRepository(AssetEntity);
332	      const offerRepository = this.txHost.tx.getRepository(BuybackOfferEntity);
333	
334	      await offerRepository.update(
335	        { id: buybackRequest.preAuthOfferId! },
336	        { acceptedAt: new Date() },
337	      );
338	
339	      // Create handover
340	      await this.assetHandoverService.create(
341	        buybackRequest.buyback.assetId,
342	        AssetHandoverType.SellerToPlatform,
343	        dto.assetHandoverOption,
344	        {
345	          fromUserId: userId,
346	          toCustodyLocationId: dto.custodyLocationId,
347	        },
348	      );
349	
350	      // Add delivery info
351	      await this.assetHandoverService.addDeliveryInfo(
352	        buybackRequest.buyback.assetId,
353	        dto,
354	      );
355	
356	      await assetRepository.save({
357	        id: buybackRequest.buyback.assetId,
358	        declarationFormId: dto.declarationFormId,
359	      });
360	
361	      await repository.save({
362	        id: buybackRequestId,
363	        status,
364	        eventsLog,
365	      });
366	
367	      await this.notificationService.send(
368	        'admins',
369	        NotificationType.BuybackRequestAdminMajorEvent,
370	        {
371	          buybackRequestId,
372	          asset: {
373	            categoryName: buybackRequest.buyback.asset?.category?.name ?? null,
374	          },
375	          status,
376	        },
377	      );
378	    });
379	  }
380	
381	  async markAsShipped(buybackRequestId: string) {
382	    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
383	
384	    const bbRequest = await repository.findOne({
385	      where: { id: buybackRequestId },
386	      relations: [
387	        'buyback',
388	        'buyback.asset',
389	        'buyback.asset.category',
390	      ],
391	    });
392	
393	    if (!bbRequest || !bbRequest.buyback) {
394	      throw new NotFoundException('Buyback request not found');
395	    }
396	
397	    return this.txHost.withTransaction(async () => {
398	      const buybackRepo = this.txHost.tx.getRepository(BuybackEntity);
399	
400	      await buybackRepo.save({
401	        id: bbRequest.buyback.id,
402	        status: BuybackStatus.SelfDropShipped,
403	        computedDetails: {
404	          ...bbRequest.buyback.computedDetails,
405	          shipmentOn: new Date(),
406	        },
407	      });
408	
409	      await this.notificationService.send(
410	        [bbRequest.buyback.sellerId!],
411	        NotificationType.BuybackAdminMinorEvent,
412	        {
413	          buybackId: bbRequest.buyback.id,
414	          asset: {
415	            categoryName: bbRequest.buyback.asset?.category?.name ?? null,
416	          },
417	          status: BuybackStatus.SelfDropShipped,
418	        },
419	      );
420	    });
421	  }
422	
423	  /**
424	   * Confirm that the user picked up the parcel.
425	   * Transitions buyback to AssetPickedUp and updates asset status.
426	   */
427	  async confirmPickup(buybackRequestId: string) {
428	    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
429	
430	    const bbRequest = await repository.findOne({
431	      where: { id: buybackRequestId },
432	      relations: [
433	        'buyback',
434	        'buyback.asset',
435	        'buyback.asset.category',
436	      ],
437	    });
438	
439	    if (!bbRequest || !bbRequest.buyback) {
440	      throw new NotFoundException('Buyback request not found');
441	    }
442	
443	    return this.txHost.withTransaction(async () => {
444	      const buybackRepository = this.txHost.tx.getRepository(BuybackEntity);
445	      const assetRepository = this.txHost.tx.getRepository(AssetEntity);
446	
447	      await buybackRepository.save({
448	        id: bbRequest.buyback.id,
449	        status: BuybackStatus.AssetPickedUp,
450	        computedDetails: {
451	          ...bbRequest.buyback.computedDetails,
452	          pickedUp: new Date(),
453	        },
454	      });
455	
456	      // Update asset status to pending return (consistent with other flows)
457	      await assetRepository.save({
458	        id: bbRequest.buyback.assetId,
459	        status: AssetStatus.PendingReturn,
460	      });
461	
462	      await this.notificationService.send(
463	        'admins',
464	        NotificationType.BuybackAdminMinorEvent,
465	        {
466	          buybackId: bbRequest.buyback.id,
467	          asset: {
468	            categoryName: bbRequest.buyback.asset?.category?.name ?? null,
469	          },
470	          status: BuybackStatus.AssetPickedUp,
471	        },
472	      );
473	    });
474	  }
475	
476	  /**
477	   * Transition buyback request to PaidBuyback.
478	   *
479	   * This marks that the user has paid for the buyback (paid-off) and allows subsequent steps
480	   * such as shipping the asset back to the user. Adds an event to the eventsLog and notifies parties.
481	   */
482	  async markPaidBuyback(buybackRequestId: string) {
483	    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
484	
485	    const bbRequest = await repository.findOne({
486	      where: { id: buybackRequestId },
487	      relations: [
488	        'buyback',
489	        'buyback.asset',
490	        'buyback.asset.category',
491	      ],
492	    });
493	
494	    if (!bbRequest || !bbRequest.buyback) {
495	      throw new NotFoundException('Buyback request not found');
496	    }
497	
498	    // Ensure allowed transition: only from FinalOfferAccepted or TransactionPending or other appropriate statuses.
499	    // Adjust list as per business requirements.
500	    const allowedFrom = [
501	      BuybackRequestStatus.FinalOfferAccepted,
502	      BuybackRequestStatus.TransactionPending,
503	    ];
504	    if (!allowedFrom.includes(bbRequest.status)) {
505	      throw new BadRequestException(
506	        'Invalid request status for marking as paid',
507	      );
508	    }
509	
510	    const buybackRepo = this.txHost.tx.getRepository(BuybackEntity);
511	
512	    await buybackRepo.save({
513	      id: bbRequest.buyback.id,
514	      status: BuybackStatus.PaidBuyback,
515	      computedDetails: {
516	        ...bbRequest.buyback.computedDetails,
517	        paidOut: new Date(),
518	      },
519	    });
520	
521	    // Notify seller about successful payment
522	    await this.notificationService.send(
523	      [bbRequest.buyback.sellerId!],
524	      NotificationType.BuybackAdminMinorEvent,
525	      {
526	        buybackId: bbRequest.buyback.id,
527	        asset: {
528	          categoryName: bbRequest.buyback.asset?.category?.name ?? null,
529	        },
530	        status: BuybackStatus.PaidBuyback,
531	      },
532	    );
533	
534	    // Notify admins that buyback was paid
535	    await this.notificationService.send(
536	      'admins',
537	      NotificationType.BuybackAdminMinorEvent,
538	      {
539	        buybackId: bbRequest.buyback.id,
540	        asset: {
541	          categoryName: bbRequest.buyback.asset?.category?.name ?? null,
542	        },
543	        status: BuybackStatus.PaidBuyback,
544	      },
545	    );
546	  }
547	
548	  /**
549	   * After marking PaidBuyback, this helper transitions the buyback to CourierShipped.
550	   * Intended to be called when shipment is created for paid buybacks.
551	   */
552	  async transitionPaidToAssetShipped(buybackRequestId: string) {
553	    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
554	
555	    const bbRequest = await repository.findOne({
556	      where: { id: buybackRequestId },
557	      relations: [
558	        'buyback',
559	        'buyback.asset',
560	        'buyback.asset.category',
561	      ],
562	    });
563	
564	    if (!bbRequest || !bbRequest.buyback) {
565	      throw new NotFoundException('Buyback request not found');
566	    }
567	
568	    if (bbRequest.buyback.status !== BuybackStatus.PaidBuyback) {
569	      throw new BadRequestException(
570	        'Buyback must be in PAID_BUYBACK status to transition to COURIER_SHIPPED',
571	      );
572	    }
573	
574	    const buybackRepo = this.txHost.tx.getRepository(BuybackEntity);
575	
576	    await buybackRepo.save({
577	      id: bbRequest.buyback.id,
578	      status: BuybackStatus.CourierShipped,
579	      computedDetails: {
580	        ...bbRequest.buyback.computedDetails,
581	        shipmentOn: new Date(),
582	      },
583	    });
584	
585	    // Notify seller about shipment
586	    await this.notificationService.send(
587	      [bbRequest.buyback.sellerId!],
588	      NotificationType.BuybackAdminMinorEvent,
589	      {
590	        buybackId: bbRequest.buyback.id,
591	        asset: {
592	          categoryName: bbRequest.buyback.asset?.category?.name ?? null,
593	        },
594	        status: BuybackStatus.CourierShipped,
595	      },
596	    );
597	  }
598	
599	  // Stage 4b
600	  async rejectPreAuthOffer(
601	    buybackRequestId: string,
602	    dto: RejectPreAuthOfferDto,
603	  ) {
604	    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
605	    const userId = this.contextService.context.user.id;
