import {
  BadRequestException,
  Injectable,
  Logger,
  NotFoundException,
} from '@nestjs/common';

import { TransactionHost } from '@nestjs-cls/transactional';

import { ContextService, TransactionalAdapterTypeOrm } from '@/modules/global';

import {
  AccountType,
  AssetEntity,
  AssetHandoverOption,
  AssetHandoverType,
  AssetStatus,
  AssetValuationEntity,
  AssetValuationStatus,
  AuthenticatorCategoryEntity,
  BuybackEntity,
  BuybackExtensionEntity,
  BuybackExtensionType,
  BuybackOfferEntity,
  BuybackRequestEntity,
  BuybackRequestStage,
  BuybackRequestStatus,
  BuybackStatus,
  BuybackType,
  EntryDirection,
  KycEntity,
  KycStatus,
  LedgerTransactionType,
  UserEntity,
  UserSetting,
} from '@/db';
import { DEFAULT_CURRENCY, convertMinorUnits } from '@/common/currency';
import { ListQuery } from '@/utils';
import {
  AcceptPreAuthOfferDto,
  BuybackSearchFilters,
  RejectPostAuthOfferDto,
  RejectPreAuthOfferDto,
} from '../types';
import { Brackets } from 'typeorm';
import {
  addBbRequestEvent,
  getBbComputedDetails,
  getBbRequestStage,
  getExtensionDates,
} from '../lib';
import { LedgerService } from '@/modules/ledger';
import { BuybackFeeCalculationService } from './buyback-fee-calculation.service';
import { AssetHandoverService } from '@/modules/asset/services/asset-handover.service';
import { NotificationService, NotificationType } from '@/modules/notification';

@Injectable()
export class BuybackRequestService {
  private logger = new Logger(BuybackRequestService.name);

  constructor(
    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    private readonly contextService: ContextService,
    private readonly ledgerService: LedgerService,
    private readonly feeCalculationService: BuybackFeeCalculationService,
    private readonly assetHandoverService: AssetHandoverService,
    private readonly notificationService: NotificationService,
  ) { }

  async markAssetShipped(buybackRequestId: string) {
    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
    const buybackRepo = this.txHost.tx.getRepository(BuybackEntity);

    const bbRequest = await repository.findOne({
      where: { id: buybackRequestId },
      relations: [
        'buyback',
        'buyback.asset',
        'buyback.asset.category',
      ],
    });

    if (!bbRequest || !bbRequest.buyback) {
      throw new NotFoundException('Buyback request not found');
    }

    await buybackRepo.save({
      id: bbRequest.buyback.id,
      status: BuybackStatus.SelfDropShipped,
      computedDetails: {
        ...bbRequest.buyback.computedDetails,
        shipmentOn: new Date(),
      },
    });

    await this.notificationService.send(
      'admins',
      NotificationType.BuybackAdminMinorEvent,
      {
        buybackId: bbRequest.buyback.id,
        asset: {
          categoryName: bbRequest.buyback.asset?.category?.name ?? null,
        },
        status: BuybackStatus.SelfDropShipped,
      },
    );
  }

  async confirmAssetPickedUp(buybackRequestId: string) {
    return this.txHost.withTransaction(async () => {
      const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
      const buybackRepo = this.txHost.tx.getRepository(BuybackEntity);
      const assetRepo = this.txHost.tx.getRepository(AssetEntity);

      const bbRequest = await repository.findOne({
        where: { id: buybackRequestId },
        relations: [
          'buyback',
          'buyback.asset',
          'buyback.asset.category',
        ],
      });

      if (!bbRequest || !bbRequest.buyback) {
        throw new NotFoundException('Buyback request not found');
      }

      await buybackRepo.save({
        id: bbRequest.buyback.id,
        status: BuybackStatus.AssetPickedUp,
        computedDetails: {
          ...bbRequest.buyback.computedDetails,
          pickedUp: new Date(),
        },
      });

      await assetRepo.save({
        id: bbRequest.buyback.assetId,
        status: AssetStatus.PendingReturn,
      });

      await this.notificationService.send(
        'admins',
        NotificationType.BuybackAdminMinorEvent,
        {
          buybackId: bbRequest.buyback.id,
          asset: {
            categoryName: bbRequest.buyback.asset?.category?.name ?? null,
          },
          status: BuybackStatus.AssetPickedUp,
        },
      );
    });
  }

  // Stage 1
  async create() {
    const buybackRequestRepository =
      this.txHost.tx.getRepository(BuybackRequestEntity);

    const stage = BuybackRequestStage.Quote;
    const status = BuybackRequestStatus.New;
    const eventsLog = addBbRequestEvent([], status);

    return buybackRequestRepository.save({
      stage,
      status,
      eventsLog,
    });
  }

  async getMany(listQuery: ListQuery, filters?: BuybackSearchFilters) {
    const userId = this.contextService.context.user.id;

    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);

    const query = repository
      .createQueryBuilder('buyback_request')
      .select([
        'buyback_request.id',
        'buyback_request.status',
        'buyback_request.stage',
        'buyback_request.createdAt',
      ])
      .leftJoin('buyback_request.buyback', 'buyback')
      .addSelect(['buyback.id', 'buyback.type', 'buyback.status'])
      .where('buyback.sellerId = :userId', { userId })
      .andWhere('buyback.status = :status', { status: BuybackStatus.Quote })
      .leftJoin('buyback.asset', 'asset')
      .addSelect(['asset.id', 'asset.meta', 'asset.categoryFields'])
      .leftJoin('asset.category', 'category')
      .addSelect(['category.id', 'category.name'])
      .leftJoin('asset.photos', 'photos')
      .addSelect(['photos.id'])
      .skip(listQuery.skip)
      .take(listQuery.take)
      .orderBy('buyback_request.createdAt', listQuery?.order || 'DESC');

    if (filters?.types) {
      query.andWhere('buyback.type IN (:...types)', { types: filters.types });
    }

    if (filters?.categories) {
      query.andWhere('category.id IN (:...categories)', {
        categories: filters.categories,
      });
    }

    if (filters?.search) {
      query.andWhere(
        new Brackets((qb) => {
          qb.where('category.name ILIKE :search')
            .orWhere("asset.categoryFields->>'brandName' ILIKE :search")
            .orWhere("asset.categoryFields->>'modelName' ILIKE :search");
        }),
        { search: `%${filters.search}%` },
      );
    }

    const [results, total] = await query.getManyAndCount();

    return {
      total,
      data: results,
      skip: listQuery.skip,
      take: listQuery.take,
    };
  }

  async getOne(buybackRequestId: string) {
    const userId = this.contextService.context.user.id;
    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);

    const buybackRequest = await repository
      .createQueryBuilder('buyback_request')
      .select([
        'buyback_request.id',
        'buyback_request.status',
        'buyback_request.stage',
        'buyback_request.createdAt',
        'buyback_request.rejectReason',
        'buyback_request.eventsLog',
      ])
      .where('buyback_request.id = :id', { id: buybackRequestId })
      .andWhere('buyback.sellerId = :userId', { userId })
      .leftJoin('buyback_request.buyback', 'buyback')
      .addSelect(['buyback.id', 'buyback.type', 'buyback.status'])
      .leftJoin('buyback.asset', 'asset')
      .addSelect([
        'asset.id',
        'asset.categoryFields',
        'asset.extras',
        'asset.meta',
        'asset.declarationFormId',
      ])
      .leftJoin('asset.category', 'category')
      .addSelect(['category.id', 'category.name'])
      .leftJoin('asset.photos', 'photos')
      .addSelect(['photos.id'])
      .leftJoin('buyback_request.preAuthOffer', 'preAuthOffer')
      .addSelect([
        'preAuthOffer.id',
        'preAuthOffer.data',
        'preAuthOffer.type',
        'preAuthOffer.expiresAt',
      ])
      .leftJoin('buyback_request.postAuthOffer', 'postAuthOffer')
      .addSelect([
        'postAuthOffer.id',
        'postAuthOffer.data',
        'postAuthOffer.type',
        'postAuthOffer.expiresAt',
      ])
      .leftJoin('asset.handovers', 'handovers')
      .addSelect([
        'handovers.id',
        'handovers.option',
        'handovers.type',
        'handovers.status',
        'handovers.courierPartnerId',
        'handovers.courierNumber',
        'handovers.visitDate',
      ])
      .leftJoin('handovers.courierPartner', 'courierPartner')
      .addSelect(['courierPartner.id', 'courierPartner.name'])
      .leftJoin('handovers.toCustodyLocation', 'toCustodyLocation')
      .addSelect(['toCustodyLocation.id', 'toCustodyLocation.name'])
      .leftJoin('toCustodyLocation.custody', 'custody')
      .addSelect(['custody.id', 'custody.name'])
      .getOne();

    if (!buybackRequest) {
      throw new NotFoundException('Buyback request not found');
    }

    return buybackRequest;
  }

  // Stage 4a
  async acceptPreAuthOffer(
    buybackRequestId: string,
    dto: AcceptPreAuthOfferDto,
  ) {
    const status = BuybackRequestStatus.PreAuthOfferAccepted;

    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
    const userId = this.contextService.context.user.id;

    const buybackRequest = await repository.findOne({
      where: { id: buybackRequestId, buyback: { sellerId: userId } },
      select: ['id', 'status', 'eventsLog'],
      relations: [
        'buyback',
        'buyback.asset',
        'buyback.asset.category',
      ],
    });

    if (!buybackRequest) {
      throw new NotFoundException('Buyback request not found');
    }

    if (buybackRequest.status !== BuybackRequestStatus.PreAuthOfferSent) {
      throw new BadRequestException('Invalid request status');
    }

    const eventsLog = addBbRequestEvent(buybackRequest.eventsLog.data, status);

    return this.txHost.withTransaction(async () => {
      const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
      const assetRepository = this.txHost.tx.getRepository(AssetEntity);
      const offerRepository = this.txHost.tx.getRepository(BuybackOfferEntity);

      await offerRepository.update(
        { id: buybackRequest.preAuthOfferId! },
        { acceptedAt: new Date() },
      );

      // Create handover
      await this.assetHandoverService.create(
        buybackRequest.buyback.assetId,
        AssetHandoverType.SellerToPlatform,
        dto.assetHandoverOption,
        {
          fromUserId: userId,
          toCustodyLocationId: dto.custodyLocationId,
        },
      );

      // Add delivery info
      await this.assetHandoverService.addDeliveryInfo(
        buybackRequest.buyback.assetId,
        dto,
      );

      await assetRepository.save({
        id: buybackRequest.buyback.assetId,
        declarationFormId: dto.declarationFormId,
      });

      await repository.save({
        id: buybackRequestId,
        status,
        eventsLog,
      });

      await this.notificationService.send(
        'admins',
        NotificationType.BuybackRequestAdminMajorEvent,
        {
          buybackRequestId,
          asset: {
            categoryName: buybackRequest.buyback.asset?.category?.name ?? null,
          },
          status,
        },
      );
    });
  }

  async markAsShipped(buybackRequestId: string) {
    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);

    const bbRequest = await repository.findOne({
      where: { id: buybackRequestId },
      relations: [
        'buyback',
        'buyback.asset',
        'buyback.asset.category',
      ],
    });

    if (!bbRequest || !bbRequest.buyback) {
      throw new NotFoundException('Buyback request not found');
    }

    return this.txHost.withTransaction(async () => {
      const buybackRepo = this.txHost.tx.getRepository(BuybackEntity);

      await buybackRepo.save({
        id: bbRequest.buyback.id,
        status: BuybackStatus.SelfDropShipped,
        computedDetails: {
          ...bbRequest.buyback.computedDetails,
          shipmentOn: new Date(),
        },
      });

      await this.notificationService.send(
        [bbRequest.buyback.sellerId!],
        NotificationType.BuybackAdminMinorEvent,
        {
          buybackId: bbRequest.buyback.id,
          asset: {
            categoryName: bbRequest.buyback.asset?.category?.name ?? null,
          },
          status: BuybackStatus.SelfDropShipped,
        },
      );
    });
  }

  /**
   * Confirm that the user picked up the parcel.
   * Transitions buyback to AssetPickedUp and updates asset status.
   */
  async confirmPickup(buybackRequestId: string) {
    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);

    const bbRequest = await repository.findOne({
      where: { id: buybackRequestId },
      relations: [
        'buyback',
        'buyback.asset',
        'buyback.asset.category',
      ],
    });

    if (!bbRequest || !bbRequest.buyback) {
      throw new NotFoundException('Buyback request not found');
    }

    return this.txHost.withTransaction(async () => {
      const buybackRepository = this.txHost.tx.getRepository(BuybackEntity);
      const assetRepository = this.txHost.tx.getRepository(AssetEntity);

      await buybackRepository.save({
        id: bbRequest.buyback.id,
        status: BuybackStatus.AssetPickedUp,
        computedDetails: {
          ...bbRequest.buyback.computedDetails,
          pickedUp: new Date(),
        },
      });

      // Update asset status to pending return (consistent with other flows)
      await assetRepository.save({
        id: bbRequest.buyback.assetId,
        status: AssetStatus.PendingReturn,
      });

      await this.notificationService.send(
        'admins',
        NotificationType.BuybackAdminMinorEvent,
        {
          buybackId: bbRequest.buyback.id,
          asset: {
            categoryName: bbRequest.buyback.asset?.category?.name ?? null,
          },
          status: BuybackStatus.AssetPickedUp,
        },
      );
    });
  }

  /**
   * Transition buyback request to PaidBuyback.
   *
   * This marks that the user has paid for the buyback (paid-off) and allows subsequent steps
   * such as shipping the asset back to the user. Adds an event to the eventsLog and notifies parties.
   */
  async markPaidBuyback(buybackRequestId: string) {
    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);

    const bbRequest = await repository.findOne({
      where: { id: buybackRequestId },
      relations: [
        'buyback',
        'buyback.asset',
        'buyback.asset.category',
      ],
    });

    if (!bbRequest || !bbRequest.buyback) {
      throw new NotFoundException('Buyback request not found');
    }

    // Ensure allowed transition: only from FinalOfferAccepted or TransactionPending or other appropriate statuses.
    // Adjust list as per business requirements.
    const allowedFrom = [
      BuybackRequestStatus.FinalOfferAccepted,
      BuybackRequestStatus.TransactionPending,
    ];
    if (!allowedFrom.includes(bbRequest.status)) {
      throw new BadRequestException(
        'Invalid request status for marking as paid',
      );
    }

    const buybackRepo = this.txHost.tx.getRepository(BuybackEntity);

    await buybackRepo.save({
      id: bbRequest.buyback.id,
      status: BuybackStatus.PaidBuyback,
      computedDetails: {
        ...bbRequest.buyback.computedDetails,
        paidOut: new Date(),
      },
    });

    // Notify seller about successful payment
    await this.notificationService.send(
      [bbRequest.buyback.sellerId!],
      NotificationType.BuybackAdminMinorEvent,
      {
        buybackId: bbRequest.buyback.id,
        asset: {
          categoryName: bbRequest.buyback.asset?.category?.name ?? null,
        },
        status: BuybackStatus.PaidBuyback,
      },
    );

    // Notify admins that buyback was paid
    await this.notificationService.send(
      'admins',
      NotificationType.BuybackAdminMinorEvent,
      {
        buybackId: bbRequest.buyback.id,
        asset: {
          categoryName: bbRequest.buyback.asset?.category?.name ?? null,
        },
        status: BuybackStatus.PaidBuyback,
      },
    );
  }

  /**
   * After marking PaidBuyback, this helper transitions the buyback to CourierShipped.
   * Intended to be called when shipment is created for paid buybacks.
   */
  async transitionPaidToAssetShipped(buybackRequestId: string) {
    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);

    const bbRequest = await repository.findOne({
      where: { id: buybackRequestId },
      relations: [
        'buyback',
        'buyback.asset',
        'buyback.asset.category',
      ],
    });

    if (!bbRequest || !bbRequest.buyback) {
      throw new NotFoundException('Buyback request not found');
    }

    if (bbRequest.buyback.status !== BuybackStatus.PaidBuyback) {
      throw new BadRequestException(
        'Buyback must be in PAID_BUYBACK status to transition to COURIER_SHIPPED',
      );
    }

    const buybackRepo = this.txHost.tx.getRepository(BuybackEntity);

    await buybackRepo.save({
      id: bbRequest.buyback.id,
      status: BuybackStatus.CourierShipped,
      computedDetails: {
        ...bbRequest.buyback.computedDetails,
        shipmentOn: new Date(),
      },
    });

    // Notify seller about shipment
    await this.notificationService.send(
      [bbRequest.buyback.sellerId!],
      NotificationType.BuybackAdminMinorEvent,
      {
        buybackId: bbRequest.buyback.id,
        asset: {
          categoryName: bbRequest.buyback.asset?.category?.name ?? null,
        },
        status: BuybackStatus.CourierShipped,
      },
    );
  }

  // Stage 4b
  async rejectPreAuthOffer(
    buybackRequestId: string,
    dto: RejectPreAuthOfferDto,
  ) {
    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
    const userId = this.contextService.context.user.id;

    const buybackRequest = await repository.findOne({
      where: { id: buybackRequestId, buyback: { sellerId: userId } },
      select: ['id', 'status', 'eventsLog'],
      relations: [
        'buyback',
        'buyback.asset',
        'buyback.asset.category',
      ],
    });

    if (!buybackRequest) {
      throw new NotFoundException('Buyback request not found');
    }

    if (buybackRequest.status !== BuybackRequestStatus.PreAuthOfferSent) {
      throw new BadRequestException('Invalid request status');
    }

    const stage = BuybackRequestStage.Rejected;

    const eventsLog = addBbRequestEvent(
      buybackRequest.eventsLog.data,
      BuybackRequestStatus.RejectedPreAuthOffer,
    );

    return this.txHost.withTransaction(async () => {
      const buybackRepository = this.txHost.tx.getRepository(BuybackEntity);
      const repository = this.txHost.tx.getRepository(BuybackRequestEntity);

      await repository.save({
        id: buybackRequestId,
        status: BuybackRequestStatus.RejectedPreAuthOffer,
        stage,
        rejectReason: dto.reason,
        eventsLog,
      });

      await buybackRepository.save({
        id: buybackRequest.buyback.id,
        status: BuybackStatus.Rejected,
      });

      await this.notificationService.send(
        'admins',
        NotificationType.BuybackRequestAdminMinorEvent,
        {
          buybackRequestId,
          asset: {
            categoryName: buybackRequest.buyback.asset?.category?.name ?? null,
          },
          status: BuybackRequestStatus.RejectedPreAuthOffer,
        },
      );
    });
  }

  // Stage 8a
  async acceptPostAuthOffer(buybackRequestId: string) {
    const status = BuybackRequestStatus.FinalOfferAccepted;

    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
    const userId = this.contextService.context.user.id;

    const kycRepository = this.txHost.tx.getRepository(KycEntity);

    const userKyc = await kycRepository.findOne({
      where: { userId },
    });

    if (!userKyc || userKyc.status !== KycStatus.Verified) {
      await repository.save({
        id: buybackRequestId,
        status: BuybackRequestStatus.KycPending,
      });

      throw new NotFoundException('You need to complete KYC first');
    }

    const buybackRequest = await repository.findOne({
      where: { id: buybackRequestId, buyback: { sellerId: userId } },
      relations: [
        'buyback',
        'postAuthOffer',
        'buyback.asset',
        'buyback.asset.category',
      ],
    });

    if (!buybackRequest) {
      throw new NotFoundException('Buyback request not found');
    }

    if (
      ![
        BuybackRequestStatus.FinalOfferSent,
        BuybackRequestStatus.KycPending,
        BuybackRequestStatus.KycApproved,
      ].includes(buybackRequest.status)
    ) {
      throw new BadRequestException('Invalid request status');
    }

    const eventsLog = addBbRequestEvent(buybackRequest.eventsLog.data, status);

    return this.txHost.withTransaction(async () => {
      const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
      const buybackRepository = this.txHost.tx.getRepository(BuybackEntity);
      const buybackExtensionRepository = this.txHost.tx.getRepository(
        BuybackExtensionEntity,
      );
      const offerRepository = this.txHost.tx.getRepository(BuybackOfferEntity);

      let bbStatus: BuybackStatus;

      switch (buybackRequest.buyback.type) {
        case BuybackType.Buyback:
          bbStatus = BuybackStatus.Active;
          break;
        case BuybackType.DirectSale:
          bbStatus = BuybackStatus.Active;
          break;
        default:
          throw new BadRequestException('Invalid buyback type');
      }

      await offerRepository.update(
        { id: buybackRequest.postAuthOffer!.id },
        { acceptedAt: new Date() },
      );

      // Update buyback
      await buybackRepository.save({
        id: buybackRequest.buyback.id,
        status: bbStatus,
      });

      // If buyback
      if (buybackRequest.buyback.type === BuybackType.Buyback) {
        // Create first extension
        const { startDate, endDate } = getExtensionDates([]);

        await buybackExtensionRepository.save({
          buybackId: buybackRequest.buyback.id,
          type: BuybackExtensionType.Default,
          month: 1,
          startDate,
          endDate,
          isFinal: true,
        });
      }

      // If direct sale
      if (buybackRequest.buyback.type === BuybackType.DirectSale) {
        const assetRepository = this.txHost.tx.getRepository(AssetEntity);

        // Move asset to unsettled
        await assetRepository.save({
          id: buybackRequest.buyback.assetId,
          status: AssetStatus.Unsettled,
        });
      }

      // Post loan disbursement to ledger
      const loanAmountUsd =
        buybackRequest.postAuthOffer!.data.toBeReceivedCents;

      const userRepository = this.txHost.tx.getRepository(UserEntity);
      const user = await userRepository.findOne({
        where: { id: userId },
        select: ['id', 'settings'],
      });
      const currency =
        user?.settings?.[UserSetting.Currency] ?? DEFAULT_CURRENCY;
      const loanAmount = convertMinorUnits(loanAmountUsd, 'USD', currency);

      await this.ledgerService.postTransaction({
        type: LedgerTransactionType.LOAN_DISBURSEMENT,
        currency,
        amountTotal: loanAmount,
        contextRef: `buyback:${buybackRequest.buyback.id}:disbursement`,
        entries: [
          {
            account: AccountType.USER_WALLET,
            direction: EntryDirection.CREDIT,
            amount: loanAmount,
            userId,
          },
          {
            account: AccountType.PLATFORM_CASH,
            direction: EntryDirection.DEBIT,
            amount: loanAmount,
            userId: null,
          },
        ],
      });

      // Compute buyback details
      await this.recomputeDetails(buybackRequest.buyback.id);

      // Update buyback request
      await repository.save({
        id: buybackRequestId,
        status,
        eventsLog,
      });

      await this.notificationService.send(
        'admins',
        NotificationType.BuybackRequestAdminMajorEvent,
        {
          buybackRequestId,
          asset: {
            categoryName: buybackRequest.buyback.asset?.category?.name ?? null,
          },
          status,
        },
      );
    });
  }

  // Stage 8b
  async rejectPostAuthOffer(
    buybackRequestId: string,
    dto: RejectPostAuthOfferDto,
  ) {
    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
    const userId = this.contextService.context.user.id;

    const buybackRequest = await repository.findOne({
      where: { id: buybackRequestId, buyback: { sellerId: userId } },
      select: ['id', 'status', 'eventsLog'],
      relations: [
        'buyback',
        'buyback.asset',
        'buyback.asset.category',
      ],
    });

    if (!buybackRequest) {
      throw new NotFoundException('Buyback request not found');
    }

    if (buybackRequest.status !== BuybackRequestStatus.FinalOfferSent) {
      throw new BadRequestException('Invalid request status');
    }

    const stage = BuybackRequestStage.Rejected;

    const eventsLog = addBbRequestEvent(
      buybackRequest.eventsLog.data,
      BuybackRequestStatus.RejectedPostAuthOffer,
    );

    return this.txHost.withTransaction(async () => {
      const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
      const buybackRepository = this.txHost.tx.getRepository(BuybackEntity);

      // Mark asset as pending return
      const assetRepository = this.txHost.tx.getRepository(AssetEntity);
      await assetRepository.save({
        id: buybackRequest.buyback.assetId,
        status: AssetStatus.PendingReturn,
      });

      // Mark buyback as rejected
      await buybackRepository.save({
        id: buybackRequest.buyback.id,
        status: BuybackStatus.Rejected,
      });

      // Mark request as rejected
      await repository.save({
        id: buybackRequestId,
        stage,
        status: BuybackRequestStatus.RejectedPostAuthOffer,
        rejectReason: dto.reason,
        eventsLog,
      });

      await this.notificationService.send(
        'admins',
        NotificationType.BuybackRequestAdminMinorEvent,
        {
          buybackRequestId,
          asset: {
            categoryName: buybackRequest.buyback.asset?.category?.name ?? null,
          },
          status: BuybackRequestStatus.RejectedPostAuthOffer,
        },
      );
    });
  }

  // Stage 2 automatic
  async sendForValuationAuto(buybackRequestId: string) {
    const status = BuybackRequestStatus.PendingValuation;

    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);

    const bbRequest = await repository.findOne({
      where: { id: buybackRequestId },
      relations: [
        'buyback',
        'buyback.asset',
        'buyback.asset.category',
      ],
    });

    if (!bbRequest) {
      this.logger.error(
        `Buyback request not found for ${buybackRequestId} when sending for auto valuation`,
      );
      return;
    }

    const authenticatorCategoryRepository = this.txHost.tx.getRepository(
      AuthenticatorCategoryEntity,
    );

    // todo: filter by min/max value when AI-made valuation amount is known
    const relevantAuthenticators = await authenticatorCategoryRepository.find({
      where: {
        categoryId: bbRequest.buyback.asset.categoryId,
      },
      relations: ['authenticator'],
    });

    const authenticatorIds = relevantAuthenticators.map(
      (a) => a.authenticatorId,
    );

    if (!authenticatorIds.length) {
      this.logger.error(
        `No authenticators found for ${buybackRequestId} when sending for auto valuation`,
      );
      return;
    }

    const eventsLog = addBbRequestEvent(bbRequest.eventsLog.data, status);

    return this.txHost.withTransaction(async () => {
      const valuationRepository =
        this.txHost.tx.getRepository(AssetValuationEntity);

      const repository = this.txHost.tx.getRepository(BuybackRequestEntity);

      const valuations = await valuationRepository.save(
        authenticatorIds.map((id) => ({
          authenticatorId: id,
          buybackRequestId,
          status: AssetValuationStatus.PendingPreAuth,
          isActive: true,
          assetId: bbRequest.buyback.assetId,
          buybackRequest: { id: buybackRequestId },
        })),
      );

      const authenticatorUserIdMap = relevantAuthenticators.reduce(
        (acc, a) => {
          acc[a.authenticatorId] = a.authenticator.userId;
          return acc;
        },
        {} as Record<string, string>,
      );

      await repository.save({
        id: buybackRequestId,
        status: status,
        stage: getBbRequestStage(status),
        eventsLog,
      });

      await Promise.all(
        valuations.map((v) =>
          this.notificationService.send(
            [authenticatorUserIdMap[v.authenticatorId]],
            NotificationType.AuthenticationRequest,
            {
              assetValuationId: v.id,
              asset: {
                categoryName: bbRequest.buyback.asset?.category?.name ?? null,
              },
            },
          ),
        ),
      );
    });
  }

  /**
   * Recompute computed details for a buyback.
   * @param buybackId
   *
   * When:
   * - Active Buyback created (bb offer accepted)
   * - Extension made
   */
  async recomputeDetails(buybackId: string) {
    const buybackRepository = this.txHost.tx.getRepository(BuybackEntity);

    const buyback = await buybackRepository.findOne({
      where: { id: buybackId },
      relations: ['request', 'request.postAuthOffer', 'extensions'],
    });

    const computedDetails = getBbComputedDetails(
      buyback!,
      this.feeCalculationService,
    );

    await buybackRepository.save({
      id: buybackId,
      computedDetails,
    });
  }
}

