import { Injectable } from '@nestjs/common';

import { TransactionHost } from '@nestjs-cls/transactional';
import { In, Or } from 'typeorm';

import { TransactionalAdapterTypeOrm } from '@/modules/global';
import { AdminEntity, MediaType, UserEntity, UserRole } from '@/db';

import {
  NOTIFICATION_MEDIA_BY_TYPE,
  NotificationData,
  NotificationMedia,
  NotificationType,
} from '../consts';
import { EmailNotificationService } from './email-notification.service';
import { PhoneNotificationService } from './phone-notification.service';
import { InAppNotificationService } from './in-app-notification.service';
import { getNotificationContent } from '../content';
import { AbstractNotificationService } from './abstract-notification.service';

@Injectable()
export class NotificationService {
  constructor(
    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    private readonly emailNotificationService: EmailNotificationService,
    private readonly phoneNotificationService: PhoneNotificationService,
    private readonly inAppNotificationService: InAppNotificationService,
  ) {}

  async send<T extends NotificationType>(
    userIds: string[] | 'admins',
    type: T,
    data: NotificationData<T>,
  ) {
    const media = NOTIFICATION_MEDIA_BY_TYPE[type];

    let users: UserEntity[];

    if (userIds === 'admins') {
      users = await this.txHost.tx
        .getRepository(UserEntity)
        .createQueryBuilder('user')
        .select(['user.id', 'user.email', 'user.phone', 'user.roles'])
        .where('user.roles && :roles', {
          roles: [UserRole.Admin, UserRole.SuperAdmin],
        })
        .getMany();
    } else {
      users = await this.txHost.tx.getRepository(UserEntity).findBy({
        id: In(userIds),
      });
    }

    await Promise.all(
      media.map(async (m) =>
        this.getService(m).send(
          users,
          type,
          data,
          getNotificationContent(type, m, data),
        ),
      ),
    );
  }

  private getService(media: NotificationMedia): AbstractNotificationService {
    switch (media) {
      case NotificationMedia.Email:
        return this.emailNotificationService;
      case NotificationMedia.Phone:
        return this.phoneNotificationService;
      case NotificationMedia.InApp:
        return this.inAppNotificationService;
    }
  }

  async sendOtp(
    mediaType: MediaType,
    dto: {
      to: string;
      otp: string;
      reason: string;
      validForMinutes: number;
    },
  ) {
    switch (mediaType) {
      case MediaType.Email:
        return this.emailNotificationService.sendOtp(dto);
      case MediaType.Phone:
        return this.phoneNotificationService.sendOtp(dto);
    }
  }

  async sendInvite(dto: {
    email: string;
    firstName: string;
    lastName: string;
    patronymic?: string | null;
    role: string;
    tempPassword: string;
  }) {
    await this.emailNotificationService.sendInvite(dto);
  }
}

import { NotificationMedia } from './notification-media.const';
import { NotificationType } from './notification-type.const';

/**
 * Defines which notification media should be used for each notification type.
 */
export const NOTIFICATION_MEDIA_BY_TYPE: Record<
  NotificationType,
  NotificationMedia[]
> = {
  // Buyback requests (seller)
  [NotificationType.BuybackRequestMajorEvent]: [
    NotificationMedia.Email,
    NotificationMedia.InApp,
  ],
  [NotificationType.BuybackRequestMinorEvent]: [NotificationMedia.InApp],

  // Buybacks (seller)
  [NotificationType.BuybackExtendReminder]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackDeadlineComingUp]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackUnsettled]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackExtendedByAdmin]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackOfferExpired]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackFinalExtensionApproved]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackFinalExtensionRejected]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],

  // KYC
  [NotificationType.KycReminder]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.KycApproved]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.KycRejected]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],

  // Authenticators
  [NotificationType.AuthenticationRequest]: [
    NotificationMedia.Email,
    NotificationMedia.InApp,
    NotificationMedia.Phone,
  ],

  // Admin
  [NotificationType.BuybackRequestAdminMinorEvent]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackRequestAdminMajorEvent]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackAdminMinorEvent]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackAdminMajorEvent]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  // Ticket
  [NotificationType.TicketClosed]: [NotificationMedia.InApp],
};

