import * as React from 'react';

import { TemplateLayout } from './components';

const COLORS = {
  text: '#000944',
  buttonBg: '#021171',
  buttonText: '#F5F3EF',
};

type Props = {
  message: string;
  link?: {
    url: string;
    text: string;
  };
};

export function GeneralTemplate({ message, link }: Props) {
  return (
    <TemplateLayout>
      <p
        style={{
          margin: '0 0 20px 0',
          fontFamily: 'Arial, sans-serif',
          fontSize: '16px',
          lineHeight: '150%',
          color: COLORS.text,
        }}
      >
        {message}
      </p>

      {link && (
        <table role="presentation" cellPadding="0" cellSpacing="0">
          <tr>
            <td>
              <a
                href={link.url}
                style={{
                  display: 'inline-block',
                  padding: '17px 12px',
                  backgroundColor: COLORS.buttonBg,
                  color: COLORS.buttonText,
                  fontFamily: 'Arial, sans-serif',
                  fontSize: '14px',
                  fontWeight: 500,
                  lineHeight: '14px',
                  letterSpacing: '-0.16px',
                  textDecoration: 'none',
                  borderRadius: '4px',
                  whiteSpace: 'nowrap',
                }}
              >
                {link.text}
              </a>
            </td>
          </tr>
        </table>
      )}
    </TemplateLayout>
  );
}

export default GeneralTemplate;

