import {
  BadRequestException,
  Body,
  Controller,
  Get,
  Param,
  Post,
  Query,
} from '@nestjs/common';
import { ApiExtraModels, ApiTags } from '@nestjs/swagger';

import { Protected } from '@/modules/auth';
import { AssetHandoverOption, UserRole } from '@/db';
import { BuybackRequestService } from '@/modules/buyback';
import { ListQuery, PaginatedResponse } from '@/utils';

import {
  AcceptPreAuthOfferRequestDto,
  BuybackRequestDetailDto,
  BuybackRequestFiltersDto,
  BuybackRequestListItemDto,
  RejectPostAuthOfferRequestDto,
  RejectPreAuthOfferRequestDto,
} from './dtos';
import {
  AcceptPostAuthOfferOpenApi,
  AcceptPreAuthOfferOpenApi,
  GetBuybackRequestOpenApi,
  GetBuybackRequestsOpenApi,
  RejectPostAuthOfferOpenApi,
  RejectPreAuthOfferOpenApi,
} from './buyback-requests.openapi';

@ApiTags('App / Buyback Requests')
@ApiExtraModels(BuybackRequestListItemDto, BuybackRequestDetailDto)
@Controller()
@Protected([UserRole.Seller])
export class BuybackRequestsController {
  constructor(private readonly buybackRequestService: BuybackRequestService) {}

  @Get('/')
  @GetBuybackRequestsOpenApi()
  async getBuybackRequests(
    @Query() listQuery: ListQuery,
    @Query() filters: BuybackRequestFiltersDto,
  ): Promise<PaginatedResponse<BuybackRequestListItemDto>> {
    const { data, total, skip, take } =
      await this.buybackRequestService.getMany(listQuery, filters);

    return {
      total,
      data: data.map(BuybackRequestListItemDto.mapFromEntity),
      skip,
      take,
    };
  }

  @Get(':id')
  @GetBuybackRequestOpenApi()
  async getBuybackRequest(
    @Param('id') id: string,
  ): Promise<BuybackRequestDetailDto> {
    const buybackRequest = await this.buybackRequestService.getOne(id);

    return BuybackRequestDetailDto.mapFromEntity(buybackRequest);
  }

  @Post(':id/accept-pre-auth-offer')
  @AcceptPreAuthOfferOpenApi()
  async acceptPreAuthOffer(
    @Param('id') id: string,
    @Body() body: AcceptPreAuthOfferRequestDto,
  ): Promise<{ success: boolean }> {
    if (body.assetHandoverOption === AssetHandoverOption.Courier) {
      if (!body.courierPartnerId) {
        throw new BadRequestException('Courier partner ID is required');
      }
      if (!body.courierNumber) {
        throw new BadRequestException('Courier tracking number is required');
      }
    }

    if (body.assetHandoverOption === AssetHandoverOption.InPerson) {
      if (!body.visitDate) {
        throw new BadRequestException('Visit date is required');
      }
    }

    await this.buybackRequestService.acceptPreAuthOffer(id, {
      declarationFormId: body.declarationFormId,
      assetHandoverOption: body.assetHandoverOption,
      custodyLocationId: body.custodyLocationId,
      courierPartnerId: body.courierPartnerId,
      courierNumber: body.courierNumber,
      visitDate: body.visitDate,
    });

    return { success: true };
  }

  @Post(':id/reject-pre-auth-offer')
  @RejectPreAuthOfferOpenApi()
  async rejectPreAuthOffer(
    @Param('id') id: string,
    @Body() body: RejectPreAuthOfferRequestDto,
  ): Promise<{ success: boolean }> {
    await this.buybackRequestService.rejectPreAuthOffer(id, {
      reason: body.reason,
    });

    return { success: true };
  }

  @Post(':id/accept-post-auth-offer')
  @AcceptPostAuthOfferOpenApi()
  async acceptPostAuthOffer(
    @Param('id') id: string,
  ): Promise<{ success: boolean }> {
    await this.buybackRequestService.acceptPostAuthOffer(id);

    return { success: true };
  }

  @Post(':id/reject-post-auth-offer')
  @RejectPostAuthOfferOpenApi()
  async rejectPostAuthOffer(
    @Param('id') id: string,
    @Body() body: RejectPostAuthOfferRequestDto,
  ): Promise<{ success: boolean }> {
    await this.buybackRequestService.rejectPostAuthOffer(id, {
      reason: body.reason,
    });

    return { success: true };
  }

  @Post(':id/mark-asset-shipped')
  async markAssetShipped(
    @Param('id') id: string,
  ): Promise<{ success: boolean }> {
    await this.buybackRequestService.markAssetShipped(id);
    return { success: true };
  }

  @Post(':id/confirm-asset-picked-up')
  async confirmAssetPickedUp(
    @Param('id') id: string,
  ): Promise<{ success: boolean }> {
    await this.buybackRequestService.confirmAssetPickedUp(id);
    return { success: true };
  }
}

