import {
  Column,
  Entity,
  Index,
  JoinColumn,
  ManyToOne,
  OneToMany,
  OneToOne,
} from 'typeorm';

import { BaseEntity } from '../utils';
import { CategoryEntity } from './category.entity';
import { FileEntity } from './file.entity';
import { BuybackEntity } from './buyback.entity';
import { UserEntity } from './user.entity';
import { AssetValuationEntity } from './asset-valuation.entity';
import { AssetHandoverEntity } from './asset-handover.entity';
import { CustodyLocationEntity } from './custody-location.entity';


export interface AssetMeta {
  photos?: {
    order: string[];
    main: string;
  } | null;
  authPhotos?: {
    order: string[];
    main: string;
  } | null;
}

export enum AssetExtraItem {
  OriginalBox = 'originalBox',
  OwnershipDocs = 'ownershipDocs',
  AuthCert = 'authCert',
}

export type AssetExtras = Record<AssetExtraItem, boolean>;

// Record<fieldId, answer>
export type AssetCategoryFields = Record<string, any>;

export enum AssetStatus {
  // Hidden in admin
  Created = 'CREATED',

  // Active
  Delivering = 'DELIVERING', // actions: DELIVERY_INFO, CONFIRM_HANDOVER
  InCustody = 'IN_CUSTODY', // actions: none
  Rejected = 'REJECTED', // actions: RETURN
  PendingReturn = 'PENDING_RETURN', // actions: none
  PendingHandover = 'PENDING_HANDOVER', // actions: RETURN
  Unsettled = 'UNSETTLED', // actions: RESELL
  Returning = 'RETURNING', // actions: DELIVERY_INFO

  InRetail = 'IN_RETAIL', // actions: none
  InAuction = 'IN_AUCTION', // actions: none

  // Released
  ReleasedViaAuction = 'RELEASED_VIA_AUCTION',
  ReleasedViaRetail = 'RELEASED_VIA_RETAIL',
  Returned = 'RETURNED',
}

@Entity({
  name: 'asset',
})
export class AssetEntity extends BaseEntity {
  @Column({
    name: 'status',
    type: 'enum',
    enum: AssetStatus,
    default: AssetStatus.Created,
  })
  status: AssetStatus;

  @ManyToOne(() => CustodyLocationEntity, (entity) => entity.assets, {
    onDelete: 'SET NULL',
    nullable: true,
  })
  @JoinColumn({ name: 'custody_location_id', referencedColumnName: 'id' })
  custodyLocation: CustodyLocationEntity | null;

  @Index('idx_asset_custody_location')
  @Column({ type: 'uuid', name: 'custody_location_id', nullable: true })
  custodyLocationId: string | null;

  @Column({
    name: 'is_authentic',
    type: 'boolean',
    nullable: true,
  })
  isAuthentic: boolean | null;

  @Column({
    name: 'category_fields',
    type: 'jsonb',
  })
  categoryFields: AssetCategoryFields;

  @Column({
    name: 'extras',
    type: 'jsonb',
  })
  extras: AssetExtras;

  // Category
  @ManyToOne(() => CategoryEntity, { onDelete: 'SET NULL' })
  @JoinColumn({ name: 'category_id', referencedColumnName: 'id' })
  category: CategoryEntity;

  @Index('idx_asset_category')
  @Column({ type: 'uuid', name: 'category_id' })
  categoryId: string;

  @OneToMany(() => FileEntity, (entity) => entity.assetPhoto)
  photos: FileEntity[];

  @OneToMany(() => FileEntity, (entity) => entity.assetAuthPhoto)
  authPhotos: FileEntity[];

  @Column({
    name: 'meta',
    type: 'jsonb',
  })
  meta: AssetMeta;

  @OneToOne(() => BuybackEntity, (entity) => entity.asset)
  buyback: BuybackEntity;

  @ManyToOne(() => UserEntity, {
    onDelete: 'SET NULL',
    nullable: true,
  })
  @JoinColumn({ name: 'seller_id', referencedColumnName: 'id' })
  seller: UserEntity | null;

  @Index('idx_asset_seller')
  @Column({ type: 'uuid', name: 'seller_id', nullable: true })
  sellerId: string | null;

  /** Proof of delivery */
  @OneToOne(() => FileEntity, { nullable: true, onDelete: 'SET NULL' })
  @JoinColumn({ name: 'pod_id', referencedColumnName: 'id' })
  pod: FileEntity;

  @Column({ type: 'uuid', name: 'pod_id', nullable: true })
  podId: string;

  /** Open box video */
  @OneToOne(() => FileEntity, {
    nullable: true,
    onDelete: 'SET NULL',
  })
  @JoinColumn({ name: 'open_box_video_id', referencedColumnName: 'id' })
  openBoxVideo: FileEntity | null;

  @Column({ type: 'uuid', name: 'open_box_video_id', nullable: true })
  openBoxVideoId: string | null;

  /** Declaration form */
  @OneToOne(() => FileEntity, {
    nullable: true,
    onDelete: 'SET NULL',
  })
  @JoinColumn({ name: 'declaration_form_id', referencedColumnName: 'id' })
  declarationForm: FileEntity | null;

  @Column({ type: 'uuid', name: 'declaration_form_id', nullable: true })
  declarationFormId: string | null;

  @OneToMany(() => AssetValuationEntity, (entity) => entity.asset)
  valuations: AssetValuationEntity[];

  @OneToMany(() => AssetHandoverEntity, (entity) => entity.asset, {})
  handovers: AssetHandoverEntity[];
}

