export type MEDIA_TYPE_TO_CONTENT<T extends NotificationMedia> =
  T extends NotificationMedia.Email
    ? {
        subject: string;
        text: string;
        link?: {
          url: string;
          text: string;
        };
      }
    : T extends NotificationMedia.InApp
      ? {
          title: string;
          body: string;
