import type { ReactElement } from 'react';

import type { EmailMetadata, EmailRenderOptions, RenderedEmail } from './types';
import { renderEmail } from './utils/render';
import {
  sanitizeSubject,
  validateEmail,
  validateEmails,
} from './utils/validation';

/**
 * Email service configuration
 */
export interface EmailServiceConfig {
  /**
   * Default sender email address
   */
  defaultFrom?: string;

  /**
   * Default reply-to email address
   */
  defaultReplyTo?: string;

  /**
   * Default rendering options
   */
  renderOptions?: EmailRenderOptions;

  /**
   * Validate emails before sending
   * @default true
   */
  validateEmails?: boolean;
}

/**
 * Email service for rendering and preparing emails
 */
export class EmailService {
  private config: EmailServiceConfig;

  constructor(config: EmailServiceConfig = {}) {
    this.config = {
      validateEmails: true,
      ...config,
    };
  }

  /**
   * Render an email template
   */
  async render(
    template: ReactElement,
    options?: EmailRenderOptions,
  ): Promise<RenderedEmail> {
    return renderEmail(template, options || this.config.renderOptions);
  }

  /**
   * Prepare an email with metadata
   */
  async prepare(
    template: ReactElement,
    metadata: Partial<EmailMetadata> & Pick<EmailMetadata, 'to' | 'subject'>,
  ): Promise<RenderedEmail> {
    // Validate emails if enabled
    if (this.config.validateEmails) {
      validateEmail(metadata.to, 'Recipient email');

      if (metadata.from) {
        validateEmail(metadata.from, 'Sender email');
      }

      if (metadata.replyTo) {
        validateEmail(metadata.replyTo, 'Reply-to email');
      }

      if (metadata.cc && metadata.cc.length > 0) {
        validateEmails(metadata.cc, 'CC email');
      }

      if (metadata.bcc && metadata.bcc.length > 0) {
        validateEmails(metadata.bcc, 'BCC email');
      }
    }

    // Render the email
    const rendered = await this.render(template);

    // Build metadata with defaults
    const emailMetadata: EmailMetadata = {
      ...metadata,
      from: metadata.from || this.config.defaultFrom || '',
      replyTo: metadata.replyTo || this.config.defaultReplyTo,
      subject: sanitizeSubject(metadata.subject),
    };

    return {
      ...rendered,
      metadata: emailMetadata,
    };
  }

  /**
   * Update the service configuration
   */
  updateConfig(config: Partial<EmailServiceConfig>): void {
    this.config = {
      ...this.config,
      ...config,
    };
  }

  /**
   * Get the current configuration
   */
  getConfig(): EmailServiceConfig {
    return { ...this.config };
  }
}

/**
 * Create a new email service instance
 */
export function createEmailService(config?: EmailServiceConfig): EmailService {
  return new EmailService(config);
}

