import { AssetExtraItem, BuybackType } from '@/db';
import {
  NotificationContentType,
  NotificationData,
  NotificationMedia,
  NotificationType,
} from '../consts';

type Data = NotificationData<NotificationType.QuoteRequestSubmitted>;

const BUYBACK_TYPE_LABEL: Record<BuybackType, string> = {
  [BuybackType.Buyback]: 'Sale with Buyback',
  [BuybackType.DirectSale]: 'Direct Sale',
};

export const EXTRA_ITEM_LABEL: Record<AssetExtraItem, string> = {
  [AssetExtraItem.OriginalBox]: 'Original Box',
  [AssetExtraItem.OwnershipDocs]: 'Ownership Documents',
  [AssetExtraItem.AuthCert]: 'Authentication Certificate',
};

export function formatExtras(extras: Data['asset']['extras']): string | undefined {
  if (!extras) return undefined;
  const items = Object.entries(extras)
    .filter(([, enabled]) => enabled)
    .map(([key]) => EXTRA_ITEM_LABEL[key as AssetExtraItem] ?? key);
  return items.length ? items.join(', ') : undefined;
}

export function getBuybackTypeLabel(type: BuybackType): string {
  return BUYBACK_TYPE_LABEL[type];
}

